# Task

Generate the static FieldSpec arrays and type_ir function pointers.

## File
`crates/dsrs-macros/src/lib.rs`

## Challenge: TypeIR Can't Be Const

TypeIR involves heap allocation. We can't create static TypeIR directly.

**Solution**: Function pointers that construct TypeIR on first call.

## Generated Code Structure

```rust
// For struct QA with output field 'confidence' that has a constraint:

// Type IR constructor for 'confidence' field
fn __qa_confidence_type_ir() -> ::dspy_rs::TypeIR {
    let base = <f32 as ::dspy_rs::baml_bridge::BamlTypeInternal>::baml_type_ir();
    // Add constraints
    ::dspy_rs::baml_bridge::with_constraints(base, vec![
        ::dspy_rs::Constraint::new_assert(
            Some("range"),
            "this >= 0.0 && this <= 1.0"
        ),
    ])
}

// Constraint specs for 'confidence'
const __QA_CONFIDENCE_CONSTRAINTS: &[::dspy_rs::ConstraintSpec] = &[
    ::dspy_rs::ConstraintSpec {
        kind: ::dspy_rs::ConstraintKind::Assert,
        label: "range",
        expression: "this >= 0.0 && this <= 1.0",
    },
];

// Output fields array
static __QA_OUTPUT_FIELDS: &[::dspy_rs::FieldSpec] = &[
    ::dspy_rs::FieldSpec {
        name: "answer",
        rust_name: "answer",
        description: "",
        type_ir: __qa_answer_type_ir,
        constraints: &[],
    },
    ::dspy_rs::FieldSpec {
        name: "confidence",
        rust_name: "confidence",
        description: "",
        type_ir: __qa_confidence_type_ir,
        constraints: __QA_CONFIDENCE_CONSTRAINTS,
    },
];
```

## Code Generation

```rust
fn generate_field_specs(
    name: &Ident,
    fields: &[ParsedField],
    kind: &str,  // "INPUT" or "OUTPUT"
) -> proc_macro2::TokenStream {
    let prefix = name.to_string().to_lowercase();
    let array_name = format_ident!("__{}_{}FIELDS", name.to_string().to_uppercase(), kind);

    let mut type_ir_fns = Vec::new();
    let mut constraint_arrays = Vec::new();
    let mut field_specs = Vec::new();

    for field in fields {
        let field_name = &field.ident;
        let field_name_str = field_name.to_string();
        let ty = &field.ty;

        // LLM-facing name (alias or original)
        let llm_name = field.alias.as_ref()
            .unwrap_or(&field_name_str);

        // Type IR function
        let type_ir_fn_name = format_ident!("__{}_{}_type_ir", prefix, field_name);

        if field.constraints.is_empty() {
            type_ir_fns.push(quote! {
                fn #type_ir_fn_name() -> ::dspy_rs::TypeIR {
                    <#ty as ::dspy_rs::baml_bridge::BamlTypeInternal>::baml_type_ir()
                }
            });
        } else {
            // Build constraints
            let constraint_tokens: Vec<_> = field.constraints.iter().map(|c| {
                let expr = &c.expression;
                let label = c.label.as_deref().unwrap_or("");
                match c.kind {
                    ConstraintKind::Check => quote! {
                        ::dspy_rs::Constraint::new_check(#label, #expr)
                    },
                    ConstraintKind::Assert => quote! {
                        ::dspy_rs::Constraint::new_assert(Some(#label), #expr)
                    },
                }
            }).collect();

            type_ir_fns.push(quote! {
                fn #type_ir_fn_name() -> ::dspy_rs::TypeIR {
                    let base = <#ty as ::dspy_rs::baml_bridge::BamlTypeInternal>::baml_type_ir();
                    ::dspy_rs::baml_bridge::with_constraints(base, vec![
                        #(#constraint_tokens),*
                    ])
                }
            });
        }

        // Constraint spec array
        let constraints_name = format_ident!("__{}_{}CONSTRAINTS", 
            name.to_string().to_uppercase(), 
            field_name.to_string().to_uppercase()
        );

        if field.constraints.is_empty() {
            constraint_arrays.push(quote! {
                const #constraints_name: &[::dspy_rs::ConstraintSpec] = &[];
            });
        } else {
            let constraint_specs: Vec<_> = field.constraints.iter().map(|c| {
                let kind = match c.kind {
                    ConstraintKind::Check => quote! { ::dspy_rs::ConstraintKind::Check },
                    ConstraintKind::Assert => quote! { ::dspy_rs::ConstraintKind::Assert },
                };
                let label = c.label.as_deref().unwrap_or("");
                let expr = &c.expression;
                quote! {
                    ::dspy_rs::ConstraintSpec {
                        kind: #kind,
                        label: #label,
                        expression: #expr,
                    }
                }
            }).collect();

            constraint_arrays.push(quote! {
                const #constraints_name: &[::dspy_rs::ConstraintSpec] = &[
                    #(#constraint_specs),*
                ];
            });
        }

        // Field spec
        let description = &field.description;
        field_specs.push(quote! {
            ::dspy_rs::FieldSpec {
                name: #llm_name,
                rust_name: #field_name_str,
                description: #description,
                type_ir: #type_ir_fn_name,
                constraints: #constraints_name,
            }
        });
    }

    quote! {
        #(#type_ir_fns)*
        #(#constraint_arrays)*

        static #array_name: &[::dspy_rs::FieldSpec] = &[
            #(#field_specs),*
        ];
    }
}
```

## with_constraints Helper

Need to verify this exists or add to baml-bridge:

```rust
// In baml-bridge/crates/bridge/src/lib.rs
pub fn with_constraints(mut ty: TypeIR, constraints: Vec<Constraint>) -> TypeIR {
    // Add constraints to the TypeIR
    ty.constraints.extend(constraints);
    ty
}
```

## Search Context
- Use morph: `TypeIR` struct definition in baml-types
- Use morph: `Constraint::new` in baml-types for constructor
- Use morph: `static.*FieldSpec` for similar patterns
